BEGIN;
DELETE FROM question_bank     WHERE module_id='c1000010-0000-0000-0000-000000000010' AND 'buildout' = ANY(tags);
DELETE FROM flashcards        WHERE module_id='c1000010-0000-0000-0000-000000000010' AND 'buildout' = ANY(tags);
DELETE FROM problem_templates WHERE module_id='c1000010-0000-0000-0000-000000000010' AND created_by='buildout:m16';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['Retracement re-establishes where the original line WAS, not where it ''should'' be','The footsteps of the original surveyor control, even over inconsistent field-note calls','Stafford v. King (1867) is the seminal Texas footsteps/dignity-of-calls case','The retracing surveyor weighs evidence; he does not have authority to move a boundary']::text[], learning_objectives=ARRAY['Define retracement and distinguish it from an original survey','State and apply the ''footsteps of the original surveyor'' doctrine under Texas law','Explain why a retracing surveyor follows evidence rather than re-creating geometry','Identify the controlling Texas authority (Stafford v. King) for retracement']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='88e2e8b2-1b43-44cb-9f84-69b4287c1bd5';
DELETE FROM lesson_blocks WHERE lesson_id='88e2e8b2-1b43-44cb-9f84-69b4287c1bd5';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=30, key_takeaways=ARRAY['The original surveyor creates boundaries; the retracing surveyor recovers them','Original survey measurements control even though modern methods are more accurate','An original monument actually set/called by the original survey outranks a record monument','Calling a later survey ''more accurate'' does not give it authority to move the line']::text[], learning_objectives=ARRAY['Contrast the authority and duty of an original surveyor with that of a retracing surveyor','Explain why measurements in the original survey control over modern, more accurate ones','Distinguish original monuments from record monuments and from later-set monuments','Recognize when a survey is legally an original act vs. a retracement']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='0e44ee50-808d-40e0-9fac-d92394584cb5';
DELETE FROM lesson_blocks WHERE lesson_id='0e44ee50-808d-40e0-9fac-d92394584cb5';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['Dignity of calls: natural monuments > artificial monuments > adjoiners > course > distance > area','The hierarchy is a rebuttable rule of construction; it yields to intent and footsteps','Corner search uses accessories (reference ties, bearing trees, mounds) to authenticate','A complete record search precedes and frames every field evidence decision']::text[], learning_objectives=ARRAY['List the principal classes of boundary evidence and rank them by reliability','Apply the dignity-of-calls hierarchy to conflicting calls in a description','Explain how monument search and accessory evidence authenticate a corner','Integrate record, physical, and parol evidence into a defensible corner determination']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='b5bf81bd-43fb-4104-bf00-21500875b87d';
DELETE FROM lesson_blocks WHERE lesson_id='b5bf81bd-43fb-4104-bf00-21500875b87d';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['Existent: physically recoverable. Obliterated: gone but recoverable from collateral evidence. Lost: no evidence remains','An obliterated corner is restored from evidence, NOT by proportioning','Proportionate measurement is reserved for truly LOST corners as a last resort','The burden is to exhaust evidence before declaring a corner lost']::text[], learning_objectives=ARRAY['Distinguish a lost corner from an obliterated corner and from an existent corner','Explain why the lost/obliterated distinction governs the restoration method','Describe how an obliterated corner is restored from collateral evidence','Recognize that proportioning applies only to genuinely lost corners']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='3557faa5-147f-430a-bc6b-57c4260d5653';
DELETE FROM lesson_blocks WHERE lesson_id='3557faa5-147f-430a-bc6b-57c4260d5653';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=40, key_takeaways=ARRAY['Proportioning distributes accumulated measurement error in proportion to record distances','Single proportion restores a lost corner on one line between two found monuments','Double proportion restores a corner controlled in two directions','Proportioning is a BLM/PLSS method and, in Texas, a last resort behind monuments and footsteps']::text[], learning_objectives=ARRAY['State when proportionate measurement is and is not appropriate','Compute a lost corner by single proportionate measurement between two found corners','Describe double proportionate measurement and apply 1-D interpolation','Recognize proportioning as a BLM/PLSS construct and a fallback in Texas']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='5dfc9628-8f23-417d-97b6-192f68ce2c10';
DELETE FROM lesson_blocks WHERE lesson_id='5dfc9628-8f23-417d-97b6-192f68ce2c10';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=30, key_takeaways=ARRAY['Senior rights: the earlier conveyance takes its full measure; the junior takes the remainder','Sequential = senior/junior governs; simultaneous (plat) = proportionate apportionment','Gaps and overlaps are resolved by seniority, not by splitting the difference','Texas applies acquiescence/agreed-boundary doctrines narrowly; the measured line usually controls']::text[], learning_objectives=ARRAY['Explain how overlaps and gaps arise and how senior/junior rights resolve them','Distinguish sequential conveyances (senior rights) from simultaneous ones (apportionment)','Describe boundary agreement, acquiescence, and estoppel as resolution doctrines','Note Texas''s narrow application of agreed-boundary and acquiescence doctrines']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='30169341-4a73-4d9b-84e7-0700156b62af';
DELETE FROM lesson_blocks WHERE lesson_id='30169341-4a73-4d9b-84e7-0700156b62af';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['Boundary/title disputes are tried as trespass-to-try-title/quiet-title in district court','The location of a survey line is a question of fact for the factfinder','The expert surveyor must base opinions on evidence and the footsteps doctrine, not advocacy','TBPELS (22 TAC Ch. 138) imposes standards of practice, professionalism, and respect for senior/junior rights']::text[], learning_objectives=ARRAY['Identify the Texas action used to try boundary/title disputes and the trial venue','Explain the surveyor''s role and duties as a retained or testifying expert witness','Describe the professional and ethical duties imposed by TBPELS rules in retracement','Recognize that the location of a boundary line is ultimately a question of fact']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='20950896-59ec-45d2-9dbc-eb3e020232b6';
DELETE FROM lesson_blocks WHERE lesson_id='20950896-59ec-45d2-9dbc-eb3e020232b6';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=40, key_takeaways=ARRAY['Real retracement requires choosing the right doctrine for the specific facts','Found monuments and evidence control; proportioning is the last resort','Senior rights govern sequential conflicts; apportionment governs simultaneous lots','A defensible determination rests on documented, weighed evidence']::text[], learning_objectives=ARRAY['Apply retracement principles to integrated, realistic boundary scenarios','Choose the correct resolution method (footsteps, evidence, seniority, proportioning) per facts','Justify a corner determination with a defensible chain of evidence','Synthesize dignity of calls, lost/obliterated classification, and senior/junior rights']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='bf1c4700-19c2-40c1-8477-19d8a2150348';
DELETE FROM lesson_blocks WHERE lesson_id='bf1c4700-19c2-40c1-8477-19d8a2150348';
  'eeee1650-0000-0000-0000-000000000001', 'Single proportionate distance to a lost corner', 'Restore a lost corner on a single line between two found monuments using single proportionate measurement.', 'Boundary Retracement — Proportionate Measurement', 'Single proportion', 'numeric_input', 'medium', 'Two found original corners are a record {{recTotal:f2}} ft apart on a straight line. A lost interior corner lies at a record distance of {{recToCorner:f2}} ft from the first found corner. The measured ground distance between the two found corners is {{measTotal:f2}} ft. Using single proportionate measurement, what is the corrected distance (ft) from the first found corner to the lost corner?', 'recToCorner*(measTotal/recTotal)', '{"decimals":2,"unit":"ft","tolerance":0.05}', '[{"name":"recTotal","type":"float","min":2000,"max":2800,"decimals":0},{"name":"fracTimes100","type":"integer","min":35,"max":65},{"name":"surplus","type":"float","min":-12,"max":14,"decimals":1}]'::jsonb, '[{"name":"recToCorner","formula":"round(recTotal*fracTimes100/100,2)"},{"name":"measTotal","formula":"round(recTotal+surplus,2)"}]'::jsonb, '[{"step_number":1,"title":"Proportion factor","formula":"measured whole ÷ record whole","calculation_template":"{{measTotal:f2}} ÷ {{recTotal:f2}}"},{"step_number":2,"title":"Corrected distance","result_template":"{{recToCorner:f2}} × ({{measTotal:f2}} ÷ {{recTotal:f2}}) = {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'Single proportion scales each record interval by the ratio of the measured whole to the record whole: {{recToCorner:f2}} × ({{measTotal:f2}} ÷ {{recTotal:f2}}) = {{_answer}} ft. The surplus/deficiency is distributed in proportion to record length.', 'c1000010-0000-0000-0000-000000000010', ARRAY['buildout','module-16','practice']::text[], true, 'buildout:m16');
  'eeee1650-0000-0000-0000-000000000002', 'Double-proportion 1-D interpolation of a corner position', 'Interpolate a lost corner position along one controlling direction (one axis of a double-proportion restoration).', 'Boundary Retracement — Proportionate Measurement', 'Double proportion (1-D)', 'numeric_input', 'medium', 'Along one controlling direction of a double-proportion restoration, two found corners are a record {{recTotal:f2}} ft apart; the lost corner''s record position is {{recFromStart:f2}} ft from the starting found corner. The measured distance between the two found corners along this direction is {{measTotal:f2}} ft. What is the interpolated (corrected) distance (ft) from the starting found corner to the lost corner along this direction?', '(recFromStart/recTotal)*measTotal', '{"decimals":2,"unit":"ft","tolerance":0.05}', '[{"name":"recTotal","type":"float","min":4800,"max":5600,"decimals":0},{"name":"fracTimes100","type":"integer","min":30,"max":70},{"name":"surplus","type":"float","min":-10,"max":12,"decimals":1}]'::jsonb, '[{"name":"recFromStart","formula":"round(recTotal*fracTimes100/100,2)"},{"name":"measTotal","formula":"round(recTotal+surplus,2)"}]'::jsonb, '[{"step_number":1,"title":"Record fraction","formula":"record-from-start ÷ record-total","calculation_template":"{{recFromStart:f2}} ÷ {{recTotal:f2}}"},{"step_number":2,"title":"Apply to measured total","result_template":"({{recFromStart:f2}} ÷ {{recTotal:f2}}) × {{measTotal:f2}} = {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'Each axis of a double proportion is a 1-D interpolation: the corrected position is the record fraction times the measured total: ({{recFromStart:f2}} ÷ {{recTotal:f2}}) × {{measTotal:f2}} = {{_answer}} ft.', 'c1000010-0000-0000-0000-000000000010', ARRAY['buildout','module-16','practice']::text[], true, 'buildout:m16');
  'eeee1650-0000-0000-0000-000000000003', 'Gap or overlap width between senior and junior lines', 'Compute the width of a gap or overlap from the measured positions of a senior and junior boundary line off a common origin.', 'Boundary Retracement — Conflict Resolution', 'Gap / overlap', 'numeric_input', 'easy', 'From a common point of beginning, the senior tract''s boundary line is measured at {{seniorPos:f2}} ft, and the junior tract''s adjoining line is measured at {{juniorPos:f2}} ft along the same direction. What is the width (ft) of the gap or overlap between the two lines?', 'abs(juniorPos-seniorPos)', '{"decimals":2,"unit":"ft","tolerance":0.02}', '[{"name":"seniorPos","type":"float","min":580,"max":620,"decimals":2},{"name":"offsetMag","type":"float","min":1.5,"max":6,"decimals":2},{"name":"dir","type":"choice","choices":[-1,1]}]'::jsonb, '[{"name":"juniorPos","formula":"round(seniorPos+dir*offsetMag,2)"}]'::jsonb, '[{"step_number":1,"title":"Difference of positions","formula":"|junior position − senior position|","calculation_template":"|{{juniorPos:f2}} − {{seniorPos:f2}}|"},{"step_number":2,"title":"Width","result_template":"= {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'The conflict width is the absolute difference between the two measured line positions: |{{juniorPos:f2}} − {{seniorPos:f2}}| = {{_answer}} ft. If the junior line is beyond the senior, the strip is a gap; if short of it, an overlap — and seniority assigns the strip in either case.', 'c1000010-0000-0000-0000-000000000010', ARRAY['buildout','module-16','practice']::text[], true, 'buildout:m16');
  'eeee1650-0000-0000-0000-000000000004', 'Corrected interior distance when a monument controls over record', 'Scale a record interior distance to fit a found monument that controls over the record distance to it.', 'Boundary Retracement — Conflict Resolution', 'Monument controls over record', 'numeric_input', 'medium', 'A block''s field notes call a record distance of {{recToMon:f2}} ft from the POB to a found original monument, with an interior lot line at a record {{recInterior:f2}} ft from the POB. The found monument is held (it controls over the record), and the measured distance from the POB to that monument is {{measToMon:f2}} ft. Holding the monument and prorating, what is the corrected distance (ft) from the POB to the interior lot line?', 'recInterior*(measToMon/recToMon)', '{"decimals":2,"unit":"ft","tolerance":0.05}', '[{"name":"recToMon","type":"float","min":380,"max":440,"decimals":0},{"name":"fracTimes100","type":"integer","min":20,"max":50},{"name":"monShift","type":"float","min":-4,"max":5,"decimals":1}]'::jsonb, '[{"name":"recInterior","formula":"round(recToMon*fracTimes100/100,2)"},{"name":"measToMon","formula":"round(recToMon+monShift,2)"}]'::jsonb, '[{"step_number":1,"title":"Control ratio","formula":"measured-to-monument ÷ record-to-monument","calculation_template":"{{measToMon:f2}} ÷ {{recToMon:f2}}"},{"step_number":2,"title":"Corrected interior distance","result_template":"{{recInterior:f2}} × ({{measToMon:f2}} ÷ {{recToMon:f2}}) = {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'When the monument controls over the record, the record-to-monument distance is replaced by the measured distance, and the interior distance is scaled by the same ratio: {{recInterior:f2}} × ({{measToMon:f2}} ÷ {{recToMon:f2}}) = {{_answer}} ft.', 'c1000010-0000-0000-0000-000000000010', ARRAY['buildout','module-16','practice']::text[], true, 'buildout:m16');
COMMIT;
SELECT 'm16 Boundary Retracement and Resolution: ' || (SELECT count(*) FROM lesson_blocks lb JOIN learning_lessons l ON l.id=lb.lesson_id WHERE l.module_id='c1000010-0000-0000-0000-000000000010') || ' blocks.' AS status;