INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1610-0001-0000-0000-000000000000', '88e2e8b2-1b43-44cb-9f84-69b4287c1bd5', 'text', '{"html":"<h3>What a retracement survey is</h3><p>A <strong>retracement</strong> (or resurvey) is a survey performed to locate the boundaries of a parcel that was <em>already created</em> by an earlier survey or conveyance. The retracing surveyor is not inventing a boundary; he is re-finding one that legally already exists on the ground. This is the single most important conceptual distinction in boundary practice: an original surveyor <em>creates</em> property lines and has wide discretion in how to run them, while a retracing surveyor merely <em>recovers</em> lines and is bound to honor decisions made decades or centuries earlier.</p><p>Because the corners and lines already exist as a matter of law, the retracing surveyor has <strong>no authority to relocate a boundary</strong> simply because modern equipment shows the original measurements were imperfect. The job is to gather the best available evidence of where the original line ran and to re-mark that location. A retracement that ''corrects'' the original by re-running record bearings and distances from scratch is professionally and legally wrong.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1610-0001-0000-0000-000000000001', '88e2e8b2-1b43-44cb-9f84-69b4287c1bd5', 'text', '{"html":"<h3>Following the footsteps of the original surveyor</h3><p>The cardinal rule of Texas retracement is to <strong>follow the footsteps of the original surveyor</strong>. The retracing surveyor asks one governing question: <em>Where did the original surveyor actually go on the ground, and what did he actually mark?</em> Where those footsteps can be ascertained from monuments, marked lines, occupation, and collateral evidence, they <strong>control</strong> — even when they are inconsistent with the bearings and distances written in the field notes.</p><p>This principle flows directly from the nature of the original grant. The parties bargained for the land the surveyor actually walked and marked, not for an idealized mathematical figure. A call in the field notes that says ''N 12&deg; E, 1000 vrs to a stake'' is only a <em>record</em> of where the surveyor went; the stake (and the evidence of it) is the better proof of his footsteps. When record and footsteps disagree, footsteps win, because the footsteps are the boundary and the record is merely a description of it.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1610-0001-0000-0000-000000000002', '88e2e8b2-1b43-44cb-9f84-69b4287c1bd5', 'accordion', '{"sections":[{"title":"Case: Stafford v. King, 30 Tex. 257 (1867)","content":"<p>The foundational Texas authority on retracement. The Texas Supreme Court held that <strong>''the actual identification of the survey, the footsteps of the surveyor upon the ground, should always be followed, by whatever rule they may be traced.''</strong> Stafford also fixed the dignity-of-calls hierarchy (natural objects, then artificial objects, then course and distance) and made clear that the hierarchy is only a tool to find the original line and the parties'' intent &mdash; it always yields to the footsteps actually run on the ground.</p>","open":true},{"title":"Modern reaffirmation: Silver Oil & Gas v. EOG Resources (Tex. App.—San Antonio 2007)","content":"<p>''The cardinal rule is that the footsteps of the original surveyor, if they can be ascertained, should be followed.'' Actual lines and corners on the ground control even if inconsistent with the field notes; only when the footsteps cannot be ascertained does the surveyor fall back on the dignity-of-calls hierarchy (natural &rarr; artificial &rarr; course &rarr; distance).</p>","open":false}]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1610-0001-0000-0000-000000000003', '88e2e8b2-1b43-44cb-9f84-69b4287c1bd5', 'callout', '{"type":"warning","text":"Texas emphasis: Because Texas titles flow from original GLO land-grant surveys (Spanish/Mexican, Republic, and State patents) and NOT from the federal PLSS township-range grid, Texas retracement centers on finding the original surveyor''s actual monuments and footsteps. PLSS-style mechanical proportioning is a last resort here, not the first move."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1610-0001-0000-0000-000000000004', '88e2e8b2-1b43-44cb-9f84-69b4287c1bd5', 'text', '{"html":"<h3>The surveyor as an evidence-weigher</h3><p>Retracement is fundamentally an exercise in <strong>evidence evaluation</strong>, not pure measurement. The competent retracing surveyor assembles every available class of evidence &mdash; original monuments, accessory marks, the record (field notes, patents, deeds, plats), adjoiner surveys, fences and occupation, parol evidence from people with knowledge, and reputation in the community &mdash; and weighs each piece for reliability. A found, undisturbed original monument is powerful; a ''pretty good fit'' to record geometry is weak. The surveyor builds a chain of reasoning that an objective professional (and ultimately a court) would accept as locating the original line.</p><p>Crucially, where the surveyor''s measurements conflict with credible physical evidence, the <strong>evidence is presumed correct and the measurement is presumed in error</strong>, unless the evidence is shown to be spurious. This humility &mdash; trusting reliable evidence over one''s own instrument &mdash; is the hallmark of sound retracement and the dividing line between a professional and a technician.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1610-0001-0000-0000-000000000005', '88e2e8b2-1b43-44cb-9f84-69b4287c1bd5', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Original survey creates the boundary; retracement recovers it by following the original surveyor''s footsteps."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1610-0001-0000-0000-000000000006', '88e2e8b2-1b43-44cb-9f84-69b4287c1bd5', 'key_takeaways', '{"title":"Key Takeaways","items":["Retracement recovers an existing boundary; it never creates or relocates one.","Follow the footsteps of the original surveyor; they control over inconsistent record calls.","Stafford v. King (1867) is the seminal Texas footsteps and dignity-of-calls authority.","Retracement is evidence evaluation: reliable physical evidence beats a fresh measurement.","Texas leans on original GLO survey/footsteps; proportioning is a fallback."]}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1610-0002-0000-0000-000000000000', '0e44ee50-808d-40e0-9fac-d92394584cb5', 'text', '{"html":"<h3>Two very different jobs</h3><p>An <strong>original survey</strong> and a <strong>retracement</strong> look similar in the field but are legally opposite acts. The <strong>original surveyor</strong> is the agent of the grantor and grantee at the moment the parcel is created. Where he sets his corners and runs his lines <em>is</em> the boundary &mdash; his footsteps fix the property forever, even if his chaining was sloppy or his compass was off. He has creative authority.</p><p>The <strong>retracing surveyor</strong> arrives later and has no such authority. He is bound by what the original surveyor did. His task is investigative: assemble evidence, reconstruct the original location, and re-mark it. He may discover the original survey contained gross error, but he cannot fix that error by moving the line &mdash; the parties'' rights vested in the original (imperfect) location. Confusing these two roles &mdash; performing an ''original'' survey when the law requires a retracement &mdash; is a leading cause of boundary litigation.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1610-0002-0000-0000-000000000001', '0e44ee50-808d-40e0-9fac-d92394584cb5', 'text', '{"html":"<h3>Why the old, less accurate measurement controls</h3><p>Students are often troubled that a 19th-century chained-and-compass measurement controls over a modern total-station or GNSS measurement. The reason is legal, not technical. The boundary was located by the <strong>original act</strong>; that act, with all its imperfections, defined what the grantee bought and what every successor in title received. A later ''more accurate'' survey measures a <em>different</em> thing &mdash; the present geometry &mdash; not the historical location that the law has already fixed.</p><p>Accuracy answers the question ''how precisely can I measure?'' Retracement answers the question ''where is the line that already exists?'' Those are different questions. A modern measurement is valuable only insofar as it helps recover the <em>original</em> location (for example, by checking the fit of found monuments). It never has authority to overrule a credible original monument simply because it is more precise.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1610-0002-0000-0000-000000000002', '0e44ee50-808d-40e0-9fac-d92394584cb5', 'table', '{"headers":["Aspect","Original surveyor","Retracing surveyor"],"rows":[["Role","Creates the boundary","Recovers the existing boundary"],["Authority over location","Discretionary — footsteps fix the line","None — bound by the original location"],["Effect of measurement error","Error becomes the boundary","Cannot ''correct'' the original by moving the line"],["Primary task","Mark and describe new corners","Gather and weigh evidence of original corners"],["Controlling evidence","The act being performed","Original monuments and the original surveyor''s footsteps"]]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1610-0002-0000-0000-000000000003', '0e44ee50-808d-40e0-9fac-d92394584cb5', 'text', '{"html":"<h3>Original monuments vs. record monuments</h3><p>An <strong>original monument</strong> is a physical object actually set or called for by the original survey to mark a corner &mdash; an iron pin driven by the original surveyor, a stone mound he built, a witness tree he blazed. A <strong>record monument</strong> is a monument that exists only as a written call (for example, a deed call to ''the east line of the Jones Survey'' or ''an iron rod set''), whose physical recovery on the ground must still be proven. When the genuine original physical monument is found undisturbed, it is the best evidence of the corner and <strong>controls over the conflicting record calls</strong> &mdash; bearing, distance, and area all yield to it.</p><p>The danger is the <strong>spurious or substitute monument</strong>: a pin set by a later surveyor, a fence corner of convenience, or a disturbed marker. The retracing surveyor must authenticate a monument (size, material, age, accessories, fit with the broader survey) before accepting it as original. A found object is only as good as the proof that it actually marks the original corner.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1610-0002-0000-0000-000000000004', '0e44ee50-808d-40e0-9fac-d92394584cb5', 'callout', '{"type":"info","text":"Heuristic: ''Monuments control over measurements, but only ORIGINAL or otherwise credible monuments control. A modern surveyor''s pin set on the wrong spot does not become controlling just because it is metal in the ground.''"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1610-0002-0000-0000-000000000005', '0e44ee50-808d-40e0-9fac-d92394584cb5', 'key_takeaways', '{"title":"Key Takeaways","items":["Original surveyors create boundaries; their footsteps are the line, errors and all.","Retracing surveyors recover boundaries and may not relocate them to ''fix'' old error.","The original (less accurate) measurement controls because it fixed the legal location.","An authenticated original monument outranks all conflicting record calls.","Authenticate before you accept: a found pin is not automatically an original corner."]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1610-0003-0000-0000-000000000000', 'b5bf81bd-43fb-4104-bf00-21500875b87d', 'text', '{"html":"<h3>The classes of boundary evidence</h3><p>Resolving a boundary is a matter of marshaling and weighing evidence. The principal classes, roughly from strongest to weakest in a typical retracement, are: (1) <strong>natural monuments</strong> (rivers, creeks, ridgelines, lakes); (2) <strong>artificial monuments</strong> (original iron pins, stone mounds, blazed bearing trees, original fence lines); (3) <strong>adjoiners</strong> (calls to an already-established adjacent survey line); (4) <strong>course</strong> (bearing/direction); (5) <strong>distance</strong>; and (6) <strong>quantity/area</strong>. Overlaid on these are the <strong>record</strong> (patents, field notes, deeds, plats), <strong>occupation</strong> (fences, buildings, long use), and <strong>parol/reputation</strong> evidence (testimony of those with knowledge; community reputation of a corner).</p><p>No class is automatically decisive. A weak class can prevail when the stronger classes are absent, ambiguous, or shown to be in error. The surveyor''s professional skill lies in judging the <em>reliability of each specific piece of evidence in the case at hand</em>, not in mechanically applying a ranked list.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1610-0003-0000-0000-000000000001', 'b5bf81bd-43fb-4104-bf00-21500875b87d', 'text', '{"html":"<h3>Dignity of calls</h3><p>When the calls <em>within a single description</em> conflict, Texas law ranks them by relative reliability &mdash; their <strong>dignity</strong>. From highest to lowest: <strong>natural monuments &rarr; artificial monuments &rarr; adjoiners &rarr; course &rarr; distance &rarr; quantity (area)</strong>. The logic is empirical: a river is hard to misidentify and does not move on paper; a marked stake is more reliable than a compass bearing; a bearing is more reliable than a chained distance (which accumulates error); and stated acreage is merely a computed by-product and the least reliable of all.</p><p>This hierarchy is a <strong>rebuttable rule of construction</strong>, not an iron law. Its entire purpose is to discover the <em>intent</em> of the grant and the <em>footsteps</em> of the original surveyor. If the instrument and surrounding circumstances show that a lower-dignity call actually expresses the parties'' intent &mdash; or if a found original monument contradicts the higher-dignity written call &mdash; the presumption yields. Stafford v. King states the order; later Texas cases refine it (inserting adjoiners and separating course from distance) but keep it subordinate to intent and footsteps.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1610-0003-0000-0000-000000000002', 'b5bf81bd-43fb-4104-bf00-21500875b87d', 'table', '{"headers":["Rank","Type of call","Why this reliability"],"rows":[["1","Natural monument (river, creek, ridge)","Hard to misidentify; fixed; rarely mis-described"],["2","Artificial monument (pin, mound, bearing tree)","Deliberately set to mark the corner; physical"],["3","Adjoiner (established adjacent line)","Ties to an independently fixed boundary of record dignity"],["4","Course (bearing)","Subject to magnetic/instrument error but fairly stable"],["5","Distance","Accumulates chaining/measurement error"],["6","Quantity / area","A computed by-product; least reliable; a check only"]]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1610-0003-0000-0000-000000000003', 'b5bf81bd-43fb-4104-bf00-21500875b87d', 'callout', '{"type":"warning","text":"Texas differs (and emphasizes): The dignity-of-calls hierarchy is only a rule of construction. It ALWAYS yields to (i) the intent of the parties shown in the instrument and (ii) the footsteps of the original surveyor where they can be found on the ground. Never apply the ranking mechanically against credible physical evidence."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1610-0003-0000-0000-000000000004', 'b5bf81bd-43fb-4104-bf00-21500875b87d', 'text', '{"html":"<h3>Corner search and accessory evidence</h3><p>Finding and <strong>authenticating</strong> a corner is the heart of field evidence work. Original surveys typically created <strong>accessories</strong> &mdash; reference ties, bearing (witness) trees with blazes and scribing, stone mounds, pits, or recorded distances to fixed natural features &mdash; precisely so a future surveyor could recover the corner even if the main monument vanished. The retracing surveyor measures from these accessories to recover the corner position and to confirm that a found monument is genuinely the original.</p><p>A disciplined search proceeds from the record: the field notes and patent describe what was set and what accessories exist; the surveyor then searches the ground systematically at and around the computed position, excavates for buried monuments, and checks accessories. Consistency among independent accessories powerfully authenticates a corner; a single unverified pin does not. When the physical corner cannot be found but accessories can, the corner is <strong>obliterated, not lost</strong>, and is recovered from those accessories (see the next lesson).</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1610-0003-0000-0000-000000000005', 'b5bf81bd-43fb-4104-bf00-21500875b87d', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: A corner authenticated by accessories — bearing trees, reference ties, and a stone mound — recovering the original position."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1610-0003-0000-0000-000000000006', 'b5bf81bd-43fb-4104-bf00-21500875b87d', 'key_takeaways', '{"title":"Key Takeaways","items":["Rank evidence by dignity: natural > artificial > adjoiner > course > distance > area.","The hierarchy is rebuttable; intent and footsteps override it.","Authenticate corners with accessories (reference ties, bearing trees, mounds).","A corner recoverable from accessories is obliterated, not lost.","Start every evidence analysis from a complete record search."]}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1610-0004-0000-0000-000000000000', '3557faa5-147f-430a-bc6b-57c4260d5653', 'text', '{"html":"<h3>Three states of a corner</h3><p>Every corner the retracing surveyor seeks is in one of three legal conditions, and the condition controls how it is restored:</p><ul><li><strong>Existent corner</strong> &mdash; the original monument (or sufficient remains of it) is physically present and recoverable. Nothing needs to be ''restored''; the corner is simply found and accepted.</li><li><strong>Obliterated corner</strong> &mdash; no trace of the original monument remains at the spot, <em>but its position can still be recovered</em> from collateral or secondary evidence: accessories (bearing trees, reference ties, mounds), the testimony of credible witnesses, undisturbed adjoiner monuments, long-standing occupation, or other reliable evidence of the original location.</li><li><strong>Lost corner</strong> &mdash; the corner is gone <em>and</em> there is no remaining evidence (physical, testimonial, or otherwise) from which its original position can be recovered. Only here may the position be re-established by measurement (proportioning).</li></ul><p>The distinction is decisive: an obliterated corner is recovered from <strong>evidence</strong>; a lost corner is re-established by <strong>proportionate measurement</strong>. Misclassifying an obliterated corner as ''lost'' &mdash; and then proportioning it &mdash; is one of the most common and serious retracement errors.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1610-0004-0000-0000-000000000001', '3557faa5-147f-430a-bc6b-57c4260d5653', 'callout', '{"type":"warning","text":"The single most important rule of this lesson: A corner is NOT lost merely because the monument is missing. It is lost only when NO evidence of its original location remains. Exhaust accessories, adjoiners, occupation, and testimony FIRST. Proportioning is a last resort, never a first move."}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1610-0004-0000-0000-000000000002', '3557faa5-147f-430a-bc6b-57c4260d5653', 'text', '{"html":"<h3>Restoring an obliterated corner</h3><p>Because an obliterated corner is recovered from evidence, the surveyor''s task is to find and trust that evidence rather than compute a position. Typical recovery paths include: measuring from <strong>recorded accessories</strong> (e.g., ''bearing tree N 30&deg; E, 22 ft'' &mdash; locate the tree or its stump/scar and reverse the tie); honoring an <strong>undisturbed adjoiner corner</strong> that the original survey called to; relying on <strong>long-standing occupation</strong> (an old fence built to the corner) corroborated by other evidence; and crediting <strong>parol testimony</strong> of persons who saw the original monument. Two or more independent lines of evidence converging on the same spot give a strong, defensible restoration.</p><p>The restored obliterated corner is placed where the <strong>evidence</strong> says the original corner was &mdash; even if that location does not perfectly fit the record bearings and distances. This is simply the footsteps doctrine applied to a missing monument: the goal is the original location, and the evidence, not the arithmetic, is the best proof of it.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1610-0004-0000-0000-000000000003', '3557faa5-147f-430a-bc6b-57c4260d5653', 'table', '{"headers":["Corner condition","Evidence remaining","Restoration method"],"rows":[["Existent","Original monument physically present","Find and accept it"],["Obliterated","No monument, but collateral evidence exists","Recover from evidence (accessories, adjoiners, occupation, testimony)"],["Lost","No recoverable evidence of original position","Re-establish by proportionate measurement (last resort)"]]}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1610-0004-0000-0000-000000000004', '3557faa5-147f-430a-bc6b-57c4260d5653', 'accordion', '{"sections":[{"title":"Texas note: footsteps before proportioning","content":"<p>Texas retracement strongly favors recovering the original location from evidence. Because Texas land is held under original GLO surveys rather than a uniform federal PLSS grid, the obliterated-corner path (recover from footsteps and collateral evidence) carries most retracements, and PLSS-style proportioning of a ''lost'' corner is genuinely a fallback. Some commentators warn that surveyors over-apply the ''must prorate'' instinct &mdash; found monuments and credible evidence should override blind proportioning.</p>","open":false}]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1610-0004-0000-0000-000000000005', '3557faa5-147f-430a-bc6b-57c4260d5653', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Classifying a corner as existent, obliterated, or lost determines whether it is found, recovered from evidence, or proportioned."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1610-0004-0000-0000-000000000006', '3557faa5-147f-430a-bc6b-57c4260d5653', 'key_takeaways', '{"title":"Key Takeaways","items":["Existent = found; obliterated = recoverable from evidence; lost = no evidence remains.","Restore obliterated corners from accessories, adjoiners, occupation, and testimony.","Only a truly lost corner is re-established by measurement (proportioning).","Misclassifying obliterated as ''lost'' and proportioning it is a serious error.","Exhaust all evidence before declaring any corner lost."]}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1610-0005-0000-0000-000000000000', '5dfc9628-8f23-417d-97b6-192f68ce2c10', 'text', '{"html":"<h3>What proportionate measurement does</h3><p><strong>Proportionate (proportional) measurement</strong> re-establishes a genuinely <em>lost</em> corner by distributing the difference between record distances and measured distances among the intervals in proportion to their record lengths. The premise is that the original surveyor''s accumulated measurement error spread itself more or less evenly along the line; so the corrected position of an interior corner should bear the same ratio to the corrected whole as the record interior interval bears to the record whole. No single interval absorbs all of the surplus or shortage.</p><p>Proportioning applies only when (a) the corner is truly <strong>lost</strong> (no recoverable evidence), and (b) the discrepancy is <strong>ordinary distributed measurement error</strong>, not an isolable gross <strong>blunder</strong>. A blunder (a transposed digit, a dropped chain length) is placed where it belongs &mdash; it is not smeared across the line. And proportioning never overrides a found monument or recoverable evidence; it is what you do when evidence has run out.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1610-0005-0000-0000-000000000001', '5dfc9628-8f23-417d-97b6-192f68ce2c10', 'equation', '{"latex":"d_{corrected} = d_{record} \\times \\frac{L_{measured}}{L_{record}}","label":"Single proportionate distance to a lost corner","display":"block"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1610-0005-0000-0000-000000000002', '5dfc9628-8f23-417d-97b6-192f68ce2c10', 'text', '{"html":"<h3>Single proportionate measurement</h3><p><strong>Single proportion</strong> (also called ''two-way'') restores a lost corner that lies on a <em>single straight line</em> between two found, undisputed monuments. Procedure:</p><ul><li>Sum the <strong>record</strong> distances between the two found monuments (record whole, L<sub>record</sub>).</li><li>Measure the <strong>actual</strong> ground distance between the same two found monuments (measured whole, L<sub>measured</sub>).</li><li>Multiply each record interval by the ratio L<sub>measured</sub> / L<sub>record</sub> to get the corrected interval.</li><li>Lay off the corrected interval(s) from a found monument to set the lost corner.</li></ul><p><em>Worked example.</em> Two found original corners are a record 2,640 ft apart; a lost corner lies at record 1,320 ft from the first. The measured distance between the found corners is 2,650.4 ft. Corrected distance to the lost corner = 1,320 &times; (2,650.4 / 2,640) = <strong>1,325.2 ft</strong> from the first found corner. The 10.4 ft of surplus is split in proportion to record length.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1610-0005-0000-0000-000000000003', '5dfc9628-8f23-417d-97b6-192f68ce2c10', 'text', '{"html":"<h3>Double proportionate measurement</h3><p><strong>Double proportion</strong> restores a lost corner that the original survey controlled in <em>two directions</em> (classically a PLSS corner common to four sections, recovered from the four nearest found corners north, south, east, and west). The latitudinal (E&ndash;W) position is proportioned independently from the two controlling corners on the east&ndash;west line, and the longitudinal (N&ndash;S) position independently from the two controlling corners on the north&ndash;south line; the two results give the corner''s coordinates.</p><p>Each direction is itself a one-dimensional proportion identical in form to single proportion. For a corner controlled along one line between two found monuments, the corrected position measured from the starting monument is:</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1610-0005-0000-0000-000000000004', '5dfc9628-8f23-417d-97b6-192f68ce2c10', 'equation', '{"latex":"p_{corrected} = \\frac{r_{from\\ start}}{r_{total}} \\times L_{measured}","label":"1-D proportional position from a found monument","display":"block"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1610-0005-0000-0000-000000000005', '5dfc9628-8f23-417d-97b6-192f68ce2c10', 'callout', '{"type":"warning","text":"Texas differs: Single and double proportionate measurement are BLM / PLSS constructs from the federal Manual of Surveying Instructions. There is NO controlling Texas Supreme Court case adopting them by name. Texas retained its own public lands (no PLSS grid), so proportioning is a last-resort fallback behind found monuments and the original surveyor''s footsteps — not the primary method."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1610-0005-0000-0000-000000000006', '5dfc9628-8f23-417d-97b6-192f68ce2c10', 'table', '{"headers":["Method","Lost corner is controlled...","Recover from"],"rows":[["Single proportion","Along ONE line","Two found monuments on that line"],["Double proportion","In TWO directions","Four found monuments (N, S, E, W)"],["Neither (do not proportion)","Corner not truly lost / blunder isolable","Evidence; place blunder where it belongs"]]}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1610-0005-0000-0000-000000000007', '5dfc9628-8f23-417d-97b6-192f68ce2c10', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Single proportion sets a lost corner on one line; double proportion sets it from four surrounding found corners."}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1610-0005-0000-0000-000000000008', '5dfc9628-8f23-417d-97b6-192f68ce2c10', 'key_takeaways', '{"title":"Key Takeaways","items":["Proportioning distributes accumulated error by the ratio of measured to record distance.","Single proportion: lost corner on one line between two found monuments.","Double proportion: lost corner controlled in two directions from four found corners.","Apply only to truly lost corners and ordinary error — not blunders, not where evidence exists.","It is a BLM/PLSS construct and, in Texas, a genuine last resort."]}'::jsonb, 8);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1610-0006-0000-0000-000000000000', '30169341-4a73-4d9b-84e7-0700156b62af', 'text', '{"html":"<h3>How overlaps and gaps happen</h3><p>An <strong>overlap</strong> occurs when two descriptions both claim the same strip of ground; a <strong>gap</strong> (hiatus) occurs when adjoining descriptions fail to meet, leaving an unclaimed strip. They arise from independent surveys run at different times, accumulated measurement error, ambiguous calls, or a grantor conveying without reconciling the new parcel to what was already conveyed. The retracing surveyor''s job is to measure the conflict and then apply the correct <em>legal</em> rule to resolve it &mdash; not to arbitrarily split the difference.</p><p>The governing rule turns on how the parcels were created. <strong>Sequential</strong> conveyances (carved out one after another over time) are resolved by <strong>senior/junior rights</strong>. <strong>Simultaneous</strong> conveyances (multiple lots created at one instant from a common recorded plat) are resolved by <strong>proportionate apportionment</strong>, because no lot is senior to another.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1610-0006-0000-0000-000000000001', '30169341-4a73-4d9b-84e7-0700156b62af', 'text', '{"html":"<h3>Senior and junior rights</h3><p>When a grantor conveys parcels in sequence, the earlier conveyance is <strong>senior</strong> and the later is <strong>junior</strong>. The senior grantee takes the <em>full measure</em> of what its description grants; the junior takes only what is <strong>left over</strong>. The principle is simply that a grantor cannot convey what he has already conveyed: having given the senior parcel away, he had only the remainder to give the junior.</p><p>Consequences for conflicts: in an <strong>overlap</strong>, the senior wins the disputed strip; the junior is cut back to the residue. In a <strong>gap</strong> created by a shortage, the senior is made whole first and the junior absorbs the deficiency. Excess and deficiency are <em>not</em> prorated between a senior and a junior &mdash; that proration is only for simultaneous, equal-dignity lots. Seniority resolves the conflict but never expands a grant beyond its own description.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1610-0006-0000-0000-000000000002', '30169341-4a73-4d9b-84e7-0700156b62af', 'table', '{"headers":["Creation","Example","Resolution rule"],"rows":[["Sequential","Metes-and-bounds carve-outs over years","Senior/junior rights — senior whole, junior takes residue"],["Simultaneous","Lots on one recorded subdivision plat","Proportionate apportionment among equal-dignity lots"],["Overlap","Two deeds claim the same strip","Senior prevails on the disputed strip"],["Gap (deficiency)","Adjoiners fall short of meeting","Senior made whole; junior absorbs the shortage"]]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1610-0006-0000-0000-000000000003', '30169341-4a73-4d9b-84e7-0700156b62af', 'text', '{"html":"<h3>Boundary agreements, acquiescence, and estoppel</h3><p>Sometimes adjoining owners resolve an uncertain line by agreement rather than by retracement. The classic doctrines are: <strong>agreed boundary</strong> (owners uncertain or disputing about the true line orally or in writing fix a line and occupy to it); <strong>acquiescence</strong> (long mutual recognition of a line, often a fence, as the boundary); and <strong>boundary by estoppel</strong> (one owner induces another''s reliance on a represented line). A valid written boundary agreement, properly executed and recorded, can settle the line for the parties and their successors.</p><p>These doctrines do not give the surveyor authority to move a record boundary; they are <em>legal</em> resolutions for a court or for the parties. The surveyor''s role is to locate and report the record line and the occupation line, identify the conflict, and let the owners and counsel pursue an agreement or suit. A surveyor should never unilaterally adopt a fence as the boundary; he reports what the evidence and record show.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1610-0006-0000-0000-000000000004', '30169341-4a73-4d9b-84e7-0700156b62af', 'callout', '{"type":"warning","text":"Texas differs: Texas applies agreed-boundary and acquiescence doctrines NARROWLY. There is no special ''innocent improver'' statute that lets a good-faith encroacher buy a strip. The surveyor''s measured boundary location is typically dispositive; title shifts only through the strict statutory adverse-possession tracks (Civ. Prac. & Rem. Code Ch. 16), not casual acquiescence."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1610-0006-0000-0000-000000000005', '30169341-4a73-4d9b-84e7-0700156b62af', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: A senior parcel takes its full measure; the junior absorbs the overlap or gap."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1610-0006-0000-0000-000000000006', '30169341-4a73-4d9b-84e7-0700156b62af', 'key_takeaways', '{"title":"Key Takeaways","items":["Overlaps and gaps are resolved by legal rule, not by splitting the difference.","Sequential conveyances: senior takes full measure, junior takes the remainder.","Simultaneous (plat) lots: apportion excess/deficiency proportionately.","Agreement, acquiescence, and estoppel can settle a line — but are owner/court matters.","Texas applies acquiescence/agreed-boundary doctrines narrowly; the measured line usually controls."]}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1610-0007-0000-0000-000000000000', '20950896-59ec-45d2-9dbc-eb3e020232b6', 'text', '{"html":"<h3>Where boundary disputes are decided</h3><p>In Texas, title and boundary disputes are tried as <strong>trespass to try title</strong> or <strong>quiet title</strong> actions in the <strong>district court</strong> (the court of general jurisdiction). Civil appeals run to a regional Court of Appeals and ultimately to the <strong>Supreme Court of Texas</strong>, which is the final authority for civil cases. (The Texas Court of Criminal Appeals never touches boundary precedent, because boundary suits are civil.) A foundational point for the testifying surveyor: the <strong>location of a survey line is a question of fact</strong> for the factfinder &mdash; the surveyor supplies expert opinion and evidence, but the jury or judge decides where the line is.</p><p>Because location is a fact question resolved on evidence, the surveyor who has done careful, well-documented retracement &mdash; following footsteps, authenticating monuments, and explaining his reasoning &mdash; is far more persuasive than one who simply re-ran record geometry. The retracement file IS the expert''s case.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1610-0007-0000-0000-000000000001', '20950896-59ec-45d2-9dbc-eb3e020232b6', 'text', '{"html":"<h3>The surveyor as expert witness</h3><p>A surveyor may serve as a <strong>consulting expert</strong> (advising counsel) or a <strong>testifying expert</strong> (offering opinions in court). The testifying expert''s duty is to the <em>truth and the methodology</em>, not to the retaining party. Opinions must rest on the recognized framework of this module: the footsteps of the original surveyor, the dignity-of-calls hierarchy as a rule of construction, authenticated monuments and accessories, and correct classification of corners as existent, obliterated, or lost. The expert explains <em>how</em> the line was located, discloses the evidence relied on, and acknowledges contrary evidence honestly.</p><p>Good practice for the expert: maintain a complete, contemporaneous record (field notes, photographs, search documentation, record research); state opinions to a reasonable degree of surveying certainty; distinguish fact from professional judgment; and never overstate. An expert who advocates beyond the evidence loses credibility and risks a complaint. The boundary surveyor''s persuasive power comes from disciplined evidence evaluation, not partisanship.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1610-0007-0000-0000-000000000002', '20950896-59ec-45d2-9dbc-eb3e020232b6', 'accordion', '{"sections":[{"title":"TBPELS — the surveyor''s professional and ethical duty","content":"<p>The <strong>Texas Board of Professional Engineers and Land Surveyors (TBPELS)</strong> regulates surveyor conduct. Its rules appear in <strong>22 Texas Administrative Code, Part 6, Chapter 138, ''Compliance and Professionalism for Surveyors,''</strong> with the professional and technical standards in <strong>Subchapter E (&sect;&sect;138.81 et seq.)</strong>. The rules require the surveyor to meet or exceed the standards of practice, to delineate the relationship between record monuments and the surveyed boundaries, to state which monuments were found and which were set, and to respect the record chain and junior/senior rights in retracement. The governing statute is the <strong>Professional Land Surveying Practices Act, Texas Occupations Code Chapter 1071</strong>; only a Registered Professional Land Surveyor (RPLS) (or, for state land, a Licensed State Land Surveyor) may prepare a metes-and-bounds description and seal the survey.</p>","open":true},{"title":"Citation hygiene for testimony","content":"<p>The former <strong>22 TAC Chapter 663</strong> surveying standards were REPEALED and merged into Chapter 138 (effective 2021) after HB 1523 (86th Leg., 2019) created TBPELS by merging the engineering and surveying boards. Citing ''&sect;663'' in 2026 is outdated &mdash; cite Chapter 138, Subchapter E. An expert who cites repealed rules undermines his own credibility.</p>","open":false}]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1610-0007-0000-0000-000000000003', '20950896-59ec-45d2-9dbc-eb3e020232b6', 'callout', '{"type":"warning","text":"Texas regulatory update: TBPELS surveying standards moved from 22 TAC Ch. 663 (repealed) to 22 TAC Ch. 138, Subchapter E (§§138.81 et seq.), effective 2021 after the 2019 merger that created TBPELS. Cite the current chapter; the old Ch. 663 citation is outdated for 2026."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1610-0007-0000-0000-000000000004', '20950896-59ec-45d2-9dbc-eb3e020232b6', 'text', '{"html":"<h3>The surveyor''s ethical duty in retracement</h3><p>The retracing surveyor occupies a position of public trust. His ethical duties &mdash; codified through TBPELS standards and the Occupations Code, and reinforced by the common law &mdash; include: <strong>honoring senior/junior rights and the record chain</strong> (not creating gaps or overlaps by ignoring prior conveyances); <strong>following the original surveyor''s footsteps</strong> rather than imposing ''better'' modern geometry; <strong>disclosing and documenting evidence</strong> fully, including evidence that cuts against the client; <strong>respecting found monuments</strong> and not setting conflicting markers carelessly; and <strong>declining to relocate boundaries</strong> he has no authority to move. A surveyor who ''pin-cushions'' a corner with a self-serving monument, or who proportions a corner that is merely obliterated, violates both good practice and his professional obligations and may face a TBPELS complaint.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1610-0007-0000-0000-000000000005', '20950896-59ec-45d2-9dbc-eb3e020232b6', 'key_takeaways', '{"title":"Key Takeaways","items":["Boundary/title disputes are tried as trespass-to-try-title/quiet-title in district court.","The location of a survey line is a question of fact for the factfinder.","The expert surveyor serves the methodology and the evidence, not the retaining party.","TBPELS rules (22 TAC Ch. 138, Subch. E) govern standards, professionalism, and senior/junior rights.","Cite current rules (Ch. 138); the repealed Ch. 663 is outdated for 2026."]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1610-0008-0000-0000-000000000000', 'bf1c4700-19c2-40c1-8477-19d8a2150348', 'text', '{"html":"<h3>Putting the module together</h3><p>Real retracement problems rarely announce which doctrine applies; the surveyor must read the facts and choose. The disciplined sequence is: (1) research the record thoroughly; (2) search for and authenticate monuments and accessories; (3) classify each corner as existent, obliterated, or lost; (4) resolve conflicting calls by dignity, always subordinate to footsteps and intent; (5) resolve overlaps/gaps by senior/junior rights (sequential) or apportionment (simultaneous); and (6) only as a last resort, proportion truly lost corners. The case studies below walk through that reasoning.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1610-0008-0000-0000-000000000001', 'bf1c4700-19c2-40c1-8477-19d8a2150348', 'accordion', '{"sections":[{"title":"Case Study 1 — Found monument vs. record bearing and distance","content":"<p><strong>Facts.</strong> A deed calls ''N 10&deg; E, 600.0 ft to an iron rod set, the NE corner of the John Doe Survey, Abstract No. 123.'' The retracing surveyor finds an undisturbed 5/8-inch iron rod with the original surveyor''s cap, 604.3 ft along a bearing of N 9&deg;45'' E, at a position corroborated by an adjoiner''s deed and an old fence corner. <strong>Resolution.</strong> The authenticated original monument is the best evidence of the corner and CONTROLS over the conflicting bearing and distance (dignity of calls: artificial monument &gt; course &gt; distance; and footsteps doctrine). The corner is at the found rod, not at the computed 600.0 ft point. <strong>Lesson:</strong> monuments control over measurements.</p>","open":true},{"title":"Case Study 2 — Obliterated vs. lost corner","content":"<p><strong>Facts.</strong> The original field notes call a corner with a bearing tree ''post oak, N 30&deg; E, 22 ft.'' No monument is found, but the surveyor locates a decayed post-oak stump with an old scribe scar at the called bearing and distance, and an adjoiner corner the survey called to. <strong>Resolution.</strong> The corner is OBLITERATED, not lost &mdash; its position is recovered from the accessory (bearing tree) and the adjoiner. It is NOT proportioned. <strong>Lesson:</strong> exhaust collateral evidence before declaring a corner lost; recover obliterated corners from evidence.</p>","open":false},{"title":"Case Study 3 — Senior/junior overlap","content":"<p><strong>Facts.</strong> A grantor conveyed Tract A in 2005 (''to the existing fence'') and Tract B in 2012 from the same parent tract; the two descriptions overlap by a 4-ft strip. <strong>Resolution.</strong> Tract A is SENIOR; it takes the full measure of its description, and the 4-ft strip belongs to A. Tract B (junior) is cut back to the residue. The excess is NOT split between them. <strong>Lesson:</strong> sequential conveyances are resolved by senior/junior rights, not proration.</p>","open":false},{"title":"Case Study 4 — Lost corner, single proportion","content":"<p><strong>Facts.</strong> An interior corner on a straight line between two found, undisputed original corners is gone, with no accessories, no occupation, and no testimony &mdash; genuinely LOST. Record whole = 2,640 ft; record to the lost corner = 1,320 ft; measured whole = 2,650.4 ft. <strong>Resolution.</strong> Re-establish by single proportionate measurement: 1,320 &times; (2,650.4 / 2,640) = <strong>1,325.2 ft</strong> from the first found corner. <strong>Lesson:</strong> proportioning is correct ONLY when the corner is truly lost and the discrepancy is ordinary distributed error.</p>","open":false}]}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1610-0008-0000-0000-000000000002', 'bf1c4700-19c2-40c1-8477-19d8a2150348', 'callout', '{"type":"info","text":"Decision rule that ties the module together: Found monument? Use it. Monument gone but evidence remains? Recover the obliterated corner from evidence. Sequential conflict? Apply senior/junior rights. Simultaneous lots? Apportion. Truly lost with only ordinary error? Proportion — last resort."}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1610-0008-0000-0000-000000000003', 'bf1c4700-19c2-40c1-8477-19d8a2150348', 'text', '{"html":"<h3>Building a defensible determination</h3><p>Whatever method the facts demand, the surveyor''s conclusion must be <strong>defensible</strong> &mdash; supportable before a fellow professional and, if needed, a court. That means documenting the record research, the search effort, the monuments and accessories found, the authentication reasoning, the classification of each corner, and the doctrine applied to each conflict. The strongest determinations show <em>convergent</em> evidence: a found monument that also fits an adjoiner call and an old fence; an obliterated corner recovered from two independent accessories. When evidence converges, the determination is robust; when it is thin, the surveyor says so plainly and proportions only where the law allows.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1610-0008-0000-0000-000000000004', 'bf1c4700-19c2-40c1-8477-19d8a2150348', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: A retracement decision tree integrating monuments, obliterated/lost classification, senior/junior rights, and proportioning."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1610-0008-0000-0000-000000000005', 'bf1c4700-19c2-40c1-8477-19d8a2150348', 'key_takeaways', '{"title":"Key Takeaways","items":["Choose the doctrine the facts demand; do not apply a single method reflexively.","Authenticated monuments control over conflicting bearings and distances.","Recover obliterated corners from evidence; proportion only truly lost corners.","Sequential conflicts → senior/junior rights; simultaneous lots → apportionment.","Document convergent evidence to make every determination defensible."]}'::jsonb, 5);
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1640-0000-0000-0000-000000000001', 'Retracement (resurvey)', 'A survey to re-establish the location of a boundary that was already created by an earlier original survey or conveyance; it recovers a line, it does not create one.', 'Re-find, do not re-invent.', 'c1000010-0000-0000-0000-000000000010', '88e2e8b2-1b43-44cb-9f84-69b4287c1bd5', 'surveying', ARRAY['buildout','module-16']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1640-0000-0000-0000-000000000002', 'Footsteps doctrine', 'The cardinal Texas rule that a retracing surveyor must locate the line where the original surveyor actually ran it on the ground, even against inconsistent field-note bearings and distances.', 'Where did he actually walk?', 'c1000010-0000-0000-0000-000000000010', '88e2e8b2-1b43-44cb-9f84-69b4287c1bd5', 'surveying', ARRAY['buildout','module-16']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1640-0000-0000-0000-000000000003', 'Stafford v. King (1867)', 'Seminal Texas Supreme Court case establishing the footsteps doctrine and the dignity-of-calls hierarchy for resolving conflicting calls.', NULL, 'c1000010-0000-0000-0000-000000000010', '88e2e8b2-1b43-44cb-9f84-69b4287c1bd5', 'surveying', ARRAY['buildout','module-16']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1640-0000-0000-0000-000000000004', 'Evidence over measurement', 'The retracement principle that reliable physical evidence of the original line is presumed correct and a conflicting fresh measurement is presumed to be the error.', NULL, 'c1000010-0000-0000-0000-000000000010', '88e2e8b2-1b43-44cb-9f84-69b4287c1bd5', 'surveying', ARRAY['buildout','module-16']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1640-0000-0000-0000-000000000005', 'Original monument', 'A physical object actually set or called for by the original survey to mark a corner; when found undisturbed it is the best evidence of the corner and controls over conflicting record calls.', 'Set by the original surveyor.', 'c1000010-0000-0000-0000-000000000010', '0e44ee50-808d-40e0-9fac-d92394584cb5', 'surveying', ARRAY['buildout','module-16']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1640-0000-0000-0000-000000000006', 'Record monument', 'A monument that exists as a written call in the field notes/deed but whose physical location on the ground must still be proven; outranked by a found, authenticated original monument.', NULL, 'c1000010-0000-0000-0000-000000000010', '0e44ee50-808d-40e0-9fac-d92394584cb5', 'surveying', ARRAY['buildout','module-16']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1640-0000-0000-0000-000000000007', 'Why old measurements control', 'Because the original survey act fixed the legal location of the boundary; a later, more accurate survey measures present geometry, not the already-vested historical line.', NULL, 'c1000010-0000-0000-0000-000000000010', '0e44ee50-808d-40e0-9fac-d92394584cb5', 'surveying', ARRAY['buildout','module-16']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1640-0000-0000-0000-000000000008', 'Spurious monument', 'A marker that appears to be a corner but was not set by (or does not credibly represent) the original survey; must be rejected after authentication fails.', NULL, 'c1000010-0000-0000-0000-000000000010', '0e44ee50-808d-40e0-9fac-d92394584cb5', 'surveying', ARRAY['buildout','module-16']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1640-0000-0000-0000-000000000009', 'Dignity of calls', 'The reliability ranking used to resolve conflicting calls within a description: natural monuments > artificial monuments > adjoiners > course > distance > quantity/area.', 'Nature beats numbers.', 'c1000010-0000-0000-0000-000000000010', 'b5bf81bd-43fb-4104-bf00-21500875b87d', 'surveying', ARRAY['buildout','module-16']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1640-0000-0000-0000-000000000010', 'Adjoiner', 'A call to an already-established adjacent survey line or boundary; ranked between artificial monuments and course in modern Texas dignity-of-calls.', 'The neighbor''s fixed line.', 'c1000010-0000-0000-0000-000000000010', 'b5bf81bd-43fb-4104-bf00-21500875b87d', 'surveying', ARRAY['buildout','module-16']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1640-0000-0000-0000-000000000011', 'Accessory (corner accessory)', 'A reference object near a corner — bearing/witness tree, reference tie, stone mound, pit — recorded so the corner can be recovered and authenticated even if the main monument is gone.', NULL, 'c1000010-0000-0000-0000-000000000010', 'b5bf81bd-43fb-4104-bf00-21500875b87d', 'surveying', ARRAY['buildout','module-16']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1640-0000-0000-0000-000000000012', 'Quantity (area) call', 'The acreage/area stated in a description; the least-reliable call because it is a computed by-product, used only as a check.', 'Lowest dignity.', 'c1000010-0000-0000-0000-000000000010', 'b5bf81bd-43fb-4104-bf00-21500875b87d', 'surveying', ARRAY['buildout','module-16']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1640-0000-0000-0000-000000000013', 'Existent corner', 'A corner whose original monument (or sufficient remains) is physically present and recoverable; simply found and accepted.', NULL, 'c1000010-0000-0000-0000-000000000010', '3557faa5-147f-430a-bc6b-57c4260d5653', 'surveying', ARRAY['buildout','module-16']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1640-0000-0000-0000-000000000014', 'Obliterated corner', 'A corner with no surviving monument but whose original position can still be recovered from collateral evidence — accessories, adjoiners, occupation, or testimony.', 'Gone but recoverable.', 'c1000010-0000-0000-0000-000000000010', '3557faa5-147f-430a-bc6b-57c4260d5653', 'surveying', ARRAY['buildout','module-16']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1640-0000-0000-0000-000000000015', 'Lost corner', 'A corner that is gone and for which NO evidence of the original location remains; only then may it be re-established by proportionate measurement.', 'No evidence left at all.', 'c1000010-0000-0000-0000-000000000010', '3557faa5-147f-430a-bc6b-57c4260d5653', 'surveying', ARRAY['buildout','module-16']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1640-0000-0000-0000-000000000016', 'Lost vs. obliterated rule', 'An obliterated corner is restored from evidence; a lost corner is restored by measurement. A corner is not ''lost'' merely because the monument is missing.', NULL, 'c1000010-0000-0000-0000-000000000010', '3557faa5-147f-430a-bc6b-57c4260d5653', 'surveying', ARRAY['buildout','module-16']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1640-0000-0000-0000-000000000017', 'Proportionate measurement', 'A method to re-establish a lost corner by distributing the difference between record and measured distances among intervals in proportion to their record lengths.', 'Spread the error by ratio.', 'c1000010-0000-0000-0000-000000000010', '5dfc9628-8f23-417d-97b6-192f68ce2c10', 'surveying', ARRAY['buildout','module-16']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1640-0000-0000-0000-000000000018', 'Single proportionate measurement', 'Restores a lost corner on a single line between two found monuments; each record interval is scaled by (measured whole / record whole).', 'Two-way, one line.', 'c1000010-0000-0000-0000-000000000010', '5dfc9628-8f23-417d-97b6-192f68ce2c10', 'surveying', ARRAY['buildout','module-16']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1640-0000-0000-0000-000000000019', 'Double proportionate measurement', 'Restores a lost corner controlled in two directions, proportioning independently between the controlling found corners in each direction (the PLSS four-corner case).', NULL, 'c1000010-0000-0000-0000-000000000010', '5dfc9628-8f23-417d-97b6-192f68ce2c10', 'surveying', ARRAY['buildout','module-16']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1640-0000-0000-0000-000000000020', 'Blunder vs. distributed error', 'Distributed measurement error is spread by proportioning; an isolable gross blunder is placed where it belongs and is NOT proportioned across the line.', NULL, 'c1000010-0000-0000-0000-000000000010', '5dfc9628-8f23-417d-97b6-192f68ce2c10', 'surveying', ARRAY['buildout','module-16']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1640-0000-0000-0000-000000000021', 'Senior rights', 'The earlier (senior) conveyance takes the full measure of its description; the later (junior) conveyance takes only the remainder, because a grantor cannot convey land already conveyed.', 'First in time, full measure.', 'c1000010-0000-0000-0000-000000000010', '30169341-4a73-4d9b-84e7-0700156b62af', 'surveying', ARRAY['buildout','module-16']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1640-0000-0000-0000-000000000022', 'Gap (hiatus) vs. overlap', 'A gap is an unclaimed strip where adjoiners fail to meet; an overlap is a strip both descriptions claim. In sequential conveyances both are resolved in the senior''s favor.', 'Hole vs. double-claim.', 'c1000010-0000-0000-0000-000000000010', '30169341-4a73-4d9b-84e7-0700156b62af', 'surveying', ARRAY['buildout','module-16']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1640-0000-0000-0000-000000000023', 'Acquiescence (boundary)', 'Long mutual recognition by adjoining owners of a line (often a fence) as the boundary; in Texas applied narrowly and not a substitute for the record line.', 'Long mutual recognition.', 'c1000010-0000-0000-0000-000000000010', '30169341-4a73-4d9b-84e7-0700156b62af', 'surveying', ARRAY['buildout','module-16']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1640-0000-0000-0000-000000000024', 'Sequential vs. simultaneous conveyance', 'Sequential parcels (carved out over time) are resolved by senior/junior rights; simultaneous parcels (one plat) are resolved by proportionate apportionment.', NULL, 'c1000010-0000-0000-0000-000000000010', '30169341-4a73-4d9b-84e7-0700156b62af', 'surveying', ARRAY['buildout','module-16']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1640-0000-0000-0000-000000000025', 'Trespass to try title', 'The Texas statutory action for trying title and boundary disputes, brought in district court; the location of a survey line within it is a question of fact.', 'Texas''s title-dispute action.', 'c1000010-0000-0000-0000-000000000010', '20950896-59ec-45d2-9dbc-eb3e020232b6', 'surveying', ARRAY['buildout','module-16']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1640-0000-0000-0000-000000000026', 'Boundary location is a question of fact', 'The Texas principle that, in a boundary suit, the factfinder decides where the line is; the surveyor supplies expert opinion and evidence, not the final ruling.', NULL, 'c1000010-0000-0000-0000-000000000010', '20950896-59ec-45d2-9dbc-eb3e020232b6', 'surveying', ARRAY['buildout','module-16']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1640-0000-0000-0000-000000000027', 'TBPELS', 'Texas Board of Professional Engineers and Land Surveyors; regulates surveyor conduct through 22 TAC Ch. 138 (standards in Subchapter E) under Occupations Code Ch. 1071.', 'The Texas licensing/regulatory board.', 'c1000010-0000-0000-0000-000000000010', '20950896-59ec-45d2-9dbc-eb3e020232b6', 'surveying', ARRAY['buildout','module-16']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1640-0000-0000-0000-000000000028', '22 TAC Chapter 138', '''Compliance and Professionalism for Surveyors'' — the current TBPELS rules (Subchapter E holds the standards of practice); replaced the repealed Chapter 663 in 2021.', 'Replaced repealed Ch. 663.', 'c1000010-0000-0000-0000-000000000010', '20950896-59ec-45d2-9dbc-eb3e020232b6', 'surveying', ARRAY['buildout','module-16']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1640-0000-0000-0000-000000000029', 'Retracement decision sequence', 'Research record → search/authenticate monuments → classify corners (existent/obliterated/lost) → resolve calls by dignity (subject to footsteps) → resolve overlaps/gaps by seniority or apportionment → proportion lost corners last.', 'Evidence first, math last.', 'c1000010-0000-0000-0000-000000000010', 'bf1c4700-19c2-40c1-8477-19d8a2150348', 'surveying', ARRAY['buildout','module-16']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1640-0000-0000-0000-000000000030', 'Defensible determination', 'A corner/line conclusion supported by documented, weighed, and ideally convergent evidence that would persuade a fellow professional or a court.', 'Convergent, documented evidence.', 'c1000010-0000-0000-0000-000000000010', 'bf1c4700-19c2-40c1-8477-19d8a2150348', 'surveying', ARRAY['buildout','module-16']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1640-0000-0000-0000-000000000031', 'Pin-cushioning', 'The poor practice of setting a new monument near an existing valid corner instead of honoring the found monument; a retracement and ethics failure.', NULL, 'c1000010-0000-0000-0000-000000000010', 'bf1c4700-19c2-40c1-8477-19d8a2150348', 'surveying', ARRAY['buildout','module-16']::text[], true, 'approved', 'intermediate');
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1630-0000-0000-0000-000000000001', 'What is the governing object of a retracement survey?', 'multiple_choice', '["To re-establish where the original boundary was actually located","To create a new, more accurate boundary using modern equipment","To correct the original surveyor''s measurement errors and move the line","To compute the boundary purely from record bearings and distances"]'::jsonb, 'To re-establish where the original boundary was actually located', 'Retracement recovers an existing boundary by following the original surveyor''s footsteps. It does not create a new line or ''correct'' the original; the line legally exists where it was first located, errors and all.', 'easy', 'c1000010-0000-0000-0000-000000000010', '88e2e8b2-1b43-44cb-9f84-69b4287c1bd5', ARRAY['buildout','module-16']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1630-0000-0000-0000-000000000002', 'Which Texas case is the seminal authority for the ''footsteps of the original surveyor'' doctrine and the dignity of calls?', 'multiple_choice', '["Stafford v. King (1867)","Motl v. Boyd (1926)","Luttes v. State (1959)","Madison v. Gordon (2001)"]'::jsonb, 'Stafford v. King (1867)', 'Stafford v. King held that the footsteps of the surveyor upon the ground should always be followed and stated the dignity-of-calls order. Motl v. Boyd is a water/gradient-boundary case, Luttes addresses coastal datums, and Madison v. Gordon concerns possession as constructive notice.', 'easy', 'c1000010-0000-0000-0000-000000000010', '88e2e8b2-1b43-44cb-9f84-69b4287c1bd5', ARRAY['buildout','module-16']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1630-0000-0000-0000-000000000003', 'When credible physical evidence of the original line conflicts with the retracing surveyor''s fresh measurement, which is presumed correct?', 'multiple_choice', '["The physical evidence; the measurement is presumed to be the error","The measurement, because modern equipment is more accurate","Whichever produces the larger acreage","Neither; the surveyor must split the difference"]'::jsonb, 'The physical evidence; the measurement is presumed to be the error', 'Reliable physical evidence of the original location controls; a conflicting modern measurement is presumed in error unless the evidence is shown to be spurious. Accuracy does not grant authority to overrule a credible original monument.', 'medium', 'c1000010-0000-0000-0000-000000000010', '88e2e8b2-1b43-44cb-9f84-69b4287c1bd5', ARRAY['buildout','module-16']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1630-0000-0000-0000-000000000004', 'Why does the original survey''s (less accurate) measurement control over a modern, more precise resurvey?', 'multiple_choice', '["Because the original act fixed the legal location of the boundary that all successors received","Because old chains were actually more accurate than total stations","Because Texas law forbids the use of GNSS in boundary work","Because the most recent survey always governs"]'::jsonb, 'Because the original act fixed the legal location of the boundary that all successors received', 'The boundary''s legal location vested at the original survey. A later survey measures present geometry, not the historical location already fixed by law, so it cannot overrule a credible original monument merely by being more precise.', 'medium', 'c1000010-0000-0000-0000-000000000010', '0e44ee50-808d-40e0-9fac-d92394584cb5', ARRAY['buildout','module-16']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1630-0000-0000-0000-000000000005', 'An original monument actually set by the original survey is found undisturbed. Compared with the conflicting record bearing and distance, the original monument:', 'multiple_choice', '["Controls over the bearing, distance, and area calls","Is ignored in favor of the written record","Controls only if it increases the parcel''s acreage","Is averaged with the record position"]'::jsonb, 'Controls over the bearing, distance, and area calls', 'A found, authenticated original monument is the best evidence of the corner and outranks the lower-dignity bearing, distance, and area calls. The written record yields to the physical footsteps.', 'easy', 'c1000010-0000-0000-0000-000000000010', '0e44ee50-808d-40e0-9fac-d92394584cb5', ARRAY['buildout','module-16']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1630-0000-0000-0000-000000000006', 'Rank the dignity of calls from highest to lowest as applied in modern Texas retracement.', 'multiple_choice', '["Natural monuments > artificial monuments > adjoiners > course > distance > area","Distance > course > area > artificial monuments > natural monuments > adjoiners","Area > distance > course > adjoiners > artificial monuments > natural monuments","Course > distance > natural monuments > artificial monuments > area > adjoiners"]'::jsonb, 'Natural monuments > artificial monuments > adjoiners > course > distance > area', 'The reliability ranking runs natural monuments, then artificial monuments, then adjoiners, then course, then distance, then quantity/area (least reliable). It is a rebuttable rule of construction subordinate to intent and footsteps.', 'medium', 'c1000010-0000-0000-0000-000000000010', 'b5bf81bd-43fb-4104-bf00-21500875b87d', ARRAY['buildout','module-16']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1630-0000-0000-0000-000000000007', 'The dignity-of-calls hierarchy is an absolute rule that always controls regardless of intent or footsteps.', 'true_false', '["True","False"]'::jsonb, 'False', 'The hierarchy is a rebuttable rule of construction. It exists to find the parties'' intent and the original surveyor''s footsteps, and it yields to both — a lower-dignity call or a found monument can control when they express the true location.', 'medium', 'c1000010-0000-0000-0000-000000000010', 'b5bf81bd-43fb-4104-bf00-21500875b87d', ARRAY['buildout','module-16']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1630-0000-0000-0000-000000000008', 'What is the primary purpose of corner accessories such as bearing trees, reference ties, and stone mounds?', 'multiple_choice', '["To recover and authenticate the corner position if the main monument is lost","To increase the stated acreage of the parcel","To mark the basis of bearing for the State Plane grid","To satisfy a tax-assessment requirement"]'::jsonb, 'To recover and authenticate the corner position if the main monument is lost', 'Accessories are recorded so a future surveyor can recover and authenticate the corner even if the primary monument vanishes. Converging accessories make an obliterated corner recoverable from evidence rather than lost.', 'easy', 'c1000010-0000-0000-0000-000000000010', 'b5bf81bd-43fb-4104-bf00-21500875b87d', ARRAY['buildout','module-16']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1630-0000-0000-0000-000000000009', 'A monument is missing, but the surveyor recovers the corner position from a recorded bearing tree and an undisturbed adjoiner corner. This corner is:', 'multiple_choice', '["Obliterated, and is restored from the collateral evidence","Lost, and must be re-established by proportionate measurement","Existent, because the monument is technically still there","Void, and the boundary cannot be located"]'::jsonb, 'Obliterated, and is restored from the collateral evidence', 'An obliterated corner has no surviving monument but a recoverable position from collateral evidence (accessories, adjoiners, occupation, testimony). It is restored from that evidence — not proportioned. Proportioning is reserved for truly lost corners.', 'medium', 'c1000010-0000-0000-0000-000000000010', '3557faa5-147f-430a-bc6b-57c4260d5653', ARRAY['buildout','module-16']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1630-0000-0000-0000-000000000010', 'A corner is properly classified as ''lost'' whenever its physical monument cannot be found.', 'true_false', '["True","False"]'::jsonb, 'False', 'A corner is lost only when NO evidence of its original position remains. If accessories, adjoiners, occupation, or testimony can recover the position, the corner is obliterated, not lost — a critical distinction that determines the restoration method.', 'medium', 'c1000010-0000-0000-0000-000000000010', '3557faa5-147f-430a-bc6b-57c4260d5653', ARRAY['buildout','module-16']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1630-0000-0000-0000-000000000011', 'Define the difference between an obliterated corner and a lost corner.', 'short_answer', '[]'::jsonb, 'An obliterated corner has no surviving monument but its position can still be recovered from collateral evidence; a lost corner has no recoverable evidence and must be re-established by proportionate measurement.', 'The obliterated/lost distinction governs the restoration method: evidence-based recovery for obliterated corners, proportionate measurement (last resort) only for genuinely lost corners.', 'medium', 'c1000010-0000-0000-0000-000000000010', '3557faa5-147f-430a-bc6b-57c4260d5653', ARRAY['buildout','module-16']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1630-0000-0000-0000-000000000012', 'Two found original corners are a record 1,320 ft apart, with a lost corner at record 660 ft from the first. The measured distance between the found corners is 1,324.0 ft. By single proportionate measurement, the corrected distance from the first found corner to the lost corner is:', 'multiple_choice', '["662.0 ft","660.0 ft","664.0 ft","658.0 ft"]'::jsonb, '662.0 ft', 'Corrected = 660 × (1,324.0 / 1,320) = 660 × 1.00303 = 662.0 ft. The 4.0 ft surplus is distributed in proportion to record length, so half of it (2.0 ft) falls in the first half-interval.', 'medium', 'c1000010-0000-0000-0000-000000000010', '5dfc9628-8f23-417d-97b6-192f68ce2c10', ARRAY['buildout','module-16']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1630-0000-0000-0000-000000000013', 'When is proportionate measurement the appropriate method to re-establish a corner?', 'multiple_choice', '["Only when the corner is truly lost and the discrepancy is ordinary distributed error","Whenever the monument is missing, regardless of other evidence","Whenever modern measurements differ from the record","For every interior corner in a subdivision"]'::jsonb, 'Only when the corner is truly lost and the discrepancy is ordinary distributed error', 'Proportioning applies only to genuinely lost corners with ordinary distributed measurement error. It never overrides a found monument or recoverable evidence, and an isolable gross blunder is placed where it belongs rather than smeared across the line.', 'medium', 'c1000010-0000-0000-0000-000000000010', '5dfc9628-8f23-417d-97b6-192f68ce2c10', ARRAY['buildout','module-16']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1630-0000-0000-0000-000000000014', 'Single and double proportionate measurement are landmark doctrines created by a famous Texas Supreme Court case.', 'true_false', '["True","False"]'::jsonb, 'False', 'Single and double proportion are BLM/PLSS constructs from the federal Manual of Surveying Instructions; no controlling Texas Supreme Court case adopts them by name. Because Texas retained its own public lands (no PLSS grid), proportioning is a last-resort fallback behind monuments and footsteps.', 'hard', 'c1000010-0000-0000-0000-000000000010', '5dfc9628-8f23-417d-97b6-192f68ce2c10', ARRAY['buildout','module-16']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1630-0000-0000-0000-000000000015', 'Double proportionate measurement is used to restore a lost corner that is:', 'multiple_choice', '["Controlled in two directions, recovered from four surrounding found corners","Located on a single straight line between two found monuments","Recoverable from a bearing tree and an adjoiner","Affected by an isolable gross blunder"]'::jsonb, 'Controlled in two directions, recovered from four surrounding found corners', 'Double proportion restores a corner controlled in two directions (classically a PLSS corner common to four sections), proportioning independently between the controlling found corners in each direction. Single proportion handles the one-line case.', 'medium', 'c1000010-0000-0000-0000-000000000010', '5dfc9628-8f23-417d-97b6-192f68ce2c10', ARRAY['buildout','module-16']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1630-0000-0000-0000-000000000016', 'A grantor conveys Tract A in 2008 and Tract B in 2015 from the same parent tract; the descriptions overlap by 3 ft. How is the overlap resolved?', 'multiple_choice', '["Tract A (senior) takes the strip; Tract B (junior) is cut back to the residue","The 3 ft strip is split equally between A and B","Tract B prevails because it is the more recent deed","The strip becomes an unclaimed gap owned by the grantor"]'::jsonb, 'Tract A (senior) takes the strip; Tract B (junior) is cut back to the residue', 'This is a sequential conveyance, so senior/junior rights govern. The senior (A) takes the full measure of its description and wins the overlap; the junior (B) takes only the remainder. Excess/deficiency is not prorated between a senior and a junior.', 'medium', 'c1000010-0000-0000-0000-000000000010', '30169341-4a73-4d9b-84e7-0700156b62af', ARRAY['buildout','module-16']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1630-0000-0000-0000-000000000017', 'Which conflict situation calls for proportionate apportionment rather than senior/junior rights?', 'multiple_choice', '["Equal-dignity lots created simultaneously on one recorded subdivision plat","Metes-and-bounds parcels carved out of a tract over many years","A senior deed overlapping a later junior deed","A gap between two independently surveyed adjoiners of different ages"]'::jsonb, 'Equal-dignity lots created simultaneously on one recorded subdivision plat', 'Simultaneous conveyances (lots of equal dignity on one plat) have no senior lot, so excess/deficiency is apportioned proportionately. Sequential carve-outs and senior/junior overlaps are resolved by seniority, not proration.', 'medium', 'c1000010-0000-0000-0000-000000000010', '30169341-4a73-4d9b-84e7-0700156b62af', ARRAY['buildout','module-16']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1630-0000-0000-0000-000000000018', 'In Texas, a surveyor may unilaterally adopt a long-standing fence as the legal boundary based on the neighbors'' casual acquiescence.', 'true_false', '["True","False"]'::jsonb, 'False', 'Texas applies acquiescence and agreed-boundary doctrines narrowly, and the surveyor has no authority to move a record boundary. The surveyor reports the record line and the occupation line; title shifts only through the strict statutory adverse-possession tracks or a valid owner agreement/court ruling.', 'medium', 'c1000010-0000-0000-0000-000000000010', '30169341-4a73-4d9b-84e7-0700156b62af', ARRAY['buildout','module-16']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1630-0000-0000-0000-000000000019', 'In a Texas boundary suit, the location of a survey line is ultimately:', 'multiple_choice', '["A question of fact decided by the factfinder","A pure question of law decided only by the Supreme Court of Texas","Determined solely by whichever survey is most recent","Decided by the Texas Court of Criminal Appeals"]'::jsonb, 'A question of fact decided by the factfinder', 'The location of a survey line is a question of fact for the jury or judge, decided on the evidence. Boundary suits are civil (so the Court of Criminal Appeals is irrelevant), and recency does not control.', 'medium', 'c1000010-0000-0000-0000-000000000010', '20950896-59ec-45d2-9dbc-eb3e020232b6', ARRAY['buildout','module-16']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1630-0000-0000-0000-000000000020', 'Which citation correctly reflects the CURRENT TBPELS surveying standards of practice as of 2026?', 'multiple_choice', '["22 TAC Chapter 138, Subchapter E (§§138.81 et seq.)","22 TAC Chapter 663 (Professional and Technical Standards)","Texas Property Code Chapter 16","BLM Manual of Surveying Instructions"]'::jsonb, '22 TAC Chapter 138, Subchapter E (§§138.81 et seq.)', 'After HB 1523 (2019) created TBPELS, the surveying standards moved to 22 TAC Ch. 138, Subchapter E (effective 2021); the former Ch. 663 was repealed. Adverse possession is in Civ. Prac. & Rem. Code Ch. 16 (not Property Code), and the BLM Manual is a federal PLSS document.', 'hard', 'c1000010-0000-0000-0000-000000000010', '20950896-59ec-45d2-9dbc-eb3e020232b6', ARRAY['buildout','module-16']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1630-0000-0000-0000-000000000021', 'Which Texas action is used to try title and boundary disputes, and in which court does it begin?', 'multiple_choice', '["Trespass to try title / quiet title, in district court","A criminal complaint, in municipal court","A small-claims action, in justice court","A licensing complaint, before TBPELS"]'::jsonb, 'Trespass to try title / quiet title, in district court', 'Title and boundary disputes are tried as trespass-to-try-title or quiet-title actions in the district court (general civil jurisdiction). A TBPELS complaint addresses surveyor conduct, not who owns the land.', 'easy', 'c1000010-0000-0000-0000-000000000010', '20950896-59ec-45d2-9dbc-eb3e020232b6', ARRAY['buildout','module-16']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1630-0000-0000-0000-000000000022', 'A deed calls ''N 10°E, 600.0 ft to an iron rod set''; the surveyor finds the original capped iron rod undisturbed at 604.3 ft, corroborated by an adjoiner and an old fence corner. The corner is at:', 'multiple_choice', '["The found original iron rod, which controls over the bearing and distance","The computed 600.0 ft point per the record distance","The midpoint between the rod and the 600.0 ft point","Wherever produces the platted acreage"]'::jsonb, 'The found original iron rod, which controls over the bearing and distance', 'An authenticated original monument is the best evidence of the corner and controls over the lower-dignity bearing and distance calls (and is reinforced by the footsteps doctrine and corroborating evidence). The corner is at the found rod, not the computed point.', 'medium', 'c1000010-0000-0000-0000-000000000010', 'bf1c4700-19c2-40c1-8477-19d8a2150348', ARRAY['buildout','module-16']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1630-0000-0000-0000-000000000023', '''Pin-cushioning'' a corner — setting a new monument next to an existing valid corner instead of honoring it — is acceptable practice if the new pin is more precisely placed.', 'true_false', '["True","False"]'::jsonb, 'False', 'Pin-cushioning is poor practice and an ethics/retracement failure. The retracing surveyor must honor a found, valid monument; setting a competing pin nearby creates ambiguity and conflicts, and precision does not justify it.', 'easy', 'c1000010-0000-0000-0000-000000000010', 'bf1c4700-19c2-40c1-8477-19d8a2150348', ARRAY['buildout','module-16']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee1660-0000-0000-0000-000000000001', 'Two found original corners are a record {{recTotal:f2}} ft apart on a straight line. A lost interior corner lies at a record distance of {{recToCorner:f2}} ft from the first found corner. The measured ground distance between the two found corners is {{measTotal:f2}} ft. Using single proportionate measurement, what is the corrected distance (ft) from the first found corner to the lost corner?', 'numeric_input', '[]'::jsonb, '0', 'Single proportion scales each record interval by the ratio of the measured whole to the record whole: {{recToCorner:f2}} × ({{measTotal:f2}} ÷ {{recTotal:f2}}) = {{_answer}} ft. The surplus/deficiency is distributed in proportion to record length.', 'medium', 'c1000010-0000-0000-0000-000000000010', NULL, ARRAY['buildout','module-16','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee1650-0000-0000-0000-000000000001', 0.05);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee1660-0000-0000-0000-000000000002', 'Along one controlling direction of a double-proportion restoration, two found corners are a record {{recTotal:f2}} ft apart; the lost corner''s record position is {{recFromStart:f2}} ft from the starting found corner. The measured distance between the two found corners along this direction is {{measTotal:f2}} ft. What is the interpolated (corrected) distance (ft) from the starting found corner to the lost corner along this direction?', 'numeric_input', '[]'::jsonb, '0', 'Each axis of a double proportion is a 1-D interpolation: the corrected position is the record fraction times the measured total: ({{recFromStart:f2}} ÷ {{recTotal:f2}}) × {{measTotal:f2}} = {{_answer}} ft.', 'medium', 'c1000010-0000-0000-0000-000000000010', NULL, ARRAY['buildout','module-16','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee1650-0000-0000-0000-000000000002', 0.05);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee1660-0000-0000-0000-000000000003', 'From a common point of beginning, the senior tract''s boundary line is measured at {{seniorPos:f2}} ft, and the junior tract''s adjoining line is measured at {{juniorPos:f2}} ft along the same direction. What is the width (ft) of the gap or overlap between the two lines?', 'numeric_input', '[]'::jsonb, '0', 'The conflict width is the absolute difference between the two measured line positions: |{{juniorPos:f2}} − {{seniorPos:f2}}| = {{_answer}} ft. If the junior line is beyond the senior, the strip is a gap; if short of it, an overlap — and seniority assigns the strip in either case.', 'easy', 'c1000010-0000-0000-0000-000000000010', NULL, ARRAY['buildout','module-16','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee1650-0000-0000-0000-000000000003', 0.02);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee1660-0000-0000-0000-000000000004', 'A block''s field notes call a record distance of {{recToMon:f2}} ft from the POB to a found original monument, with an interior lot line at a record {{recInterior:f2}} ft from the POB. The found monument is held (it controls over the record), and the measured distance from the POB to that monument is {{measToMon:f2}} ft. Holding the monument and prorating, what is the corrected distance (ft) from the POB to the interior lot line?', 'numeric_input', '[]'::jsonb, '0', 'When the monument controls over the record, the record-to-monument distance is replaced by the measured distance, and the interior distance is scaled by the same ratio: {{recInterior:f2}} × ({{measToMon:f2}} ÷ {{recToMon:f2}}) = {{_answer}} ft.', 'medium', 'c1000010-0000-0000-0000-000000000010', NULL, ARRAY['buildout','module-16','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee1650-0000-0000-0000-000000000004', 0.05);
